const raw = input.trim().replace(/[,_]/g, '');
const m = raw.match(/^([\d.]+)\s*(bytes?|b|kb|mb|gb|kib|mib|gib)?$/i);
if (!m) return { output: '', error: 'Enter a byte count, e.g. "1048576" or "1.5 GB".' };
const val = parseFloat(m[1]);
const unit = (m[2] || 'b').toLowerCase();
const MULTIPLIERS = {
  b: 1, byte: 1, bytes: 1,
  kb: 1e3, mb: 1e6, gb: 1e9, tb: 1e12,
  kib: 1024, mib: 1024**2, gib: 1024**3, tib: 1024**4,
};
const bytes = val * (MULTIPLIERS[unit] || 1);

function si(b) {
  const units = ['B','KB','MB','GB','TB','PB'];
  let i = 0;
  while (b >= 1000 && i < units.length - 1) { b /= 1000; i++; }
  return b.toFixed(i > 0 ? 3 : 0) + ' ' + units[i];
}
function binary(b) {
  const units = ['B','KiB','MiB','GiB','TiB','PiB'];
  let i = 0;
  while (b >= 1024 && i < units.length - 1) { b /= 1024; i++; }
  return b.toFixed(i > 0 ? 4 : 0) + ' ' + units[i];
}

const lines = [
  `Raw bytes:     ${bytes.toLocaleString()} B`,
  `SI (decimal):  ${si(bytes)}`,
  `Binary (IEC):  ${binary(bytes)}`,
  '',
  '--- All SI ---',
  `  Kilobytes:   ${(bytes / 1e3).toFixed(3)} KB`,
  `  Megabytes:   ${(bytes / 1e6).toFixed(6)} MB`,
  `  Gigabytes:   ${(bytes / 1e9).toFixed(9)} GB`,
  '',
  '--- All Binary ---',
  `  Kibibytes:   ${(bytes / 1024).toFixed(4)} KiB`,
  `  Mebibytes:   ${(bytes / 1024**2).toFixed(6)} MiB`,
  `  Gibibytes:   ${(bytes / 1024**3).toFixed(9)} GiB`,
];
return { output: lines.join('\n'), outputLanguage: 'text' };
